<?php include __DIR__ . '/../../includes/header.php'; require_permission('reportes.ver');
$from=$_GET['from']??date('Y-m-01'); $to=$_GET['to']??date('Y-m-d'); $stmt=$pdo->prepare("SELECT * FROM v_accesos_detalle WHERE DATE(fecha_hora_ingreso) BETWEEN ? AND ? ORDER BY fecha_hora_ingreso DESC");$stmt->execute([$from,$to]); $rows=$stmt->fetchAll(); ?>
<h1>Reportes</h1><div class="card"><form method="GET" class="two-col"><div><label>Desde</label><input type="date" name="from" value="<?= e($from) ?>"></div><div><label>Hasta</label><input type="date" name="to" value="<?= e($to) ?>"></div><div><button>Filtrar</button></div></form></div><div class="card"><h2>Reporte de accesos</h2><table><tr><th>Persona</th><th>Tipo</th><th>Área</th><th>Ingreso</th><th>Salida</th><th>Estado</th><th>Método</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['persona']) ?></td><td><?= e($r['tipo_persona']) ?></td><td><?= e($r['area']??'General') ?></td><td><?= e($r['fecha_hora_ingreso']) ?></td><td><?= e($r['fecha_hora_salida']) ?></td><td><?= e($r['estado_acceso']) ?></td><td><?= e($r['metodo_validacion']) ?></td></tr><?php endforeach; ?></table></div><?php include __DIR__ . '/../../includes/footer.php'; ?>
